rust_intro.cheat:
// Quick practical Rust cheat
// Tooling
// rustup: install and manage toolchains
// cargo new myapp --bin; cargo run; cargo build --release; cargo test

// Common patterns
// - Prefer &str and &T for borrowed views, String/Vec for owned data
// - Use Result<T,E> and '?' for error propagation
// - Use iterators, try to avoid cloning by design

// Release tips
// - Use cargo build --release
// - Consider [profile.release] lto = true, codegen-units = 1 for size/perf

examples.code:
// cargo commands
// cargo new myapp --bin
// cd myapp
// cargo run

// quick Result usage
use std::fs::read_to_string;
fn read(path: &str) -> std::io::Result<String> { read_to_string(path) }

