rust_ownership.cheat:
// Ownership practical cheat
// - Move: let a = v; let b = a; // a moved unless Copy
// - Borrow: &T for read, &mut T for mutable borrow
// - Rules: many &T or one &mut T at a time
// - Use Rc/Arc for shared ownership, RefCell/Mutex for interior mutability

rust_concurrency.cheat:
// Concurrency cheat
// - Thread: std::thread::spawn(move || { ... }).join().unwrap();
// - Channels: std::sync::mpsc or crossbeam for performance
// - Async: async fn, .await, run on tokio or async-std
// - Ensure types across threads implement Send/Sync

