rust_traits.cheat:
// Traits & generics cheat
// trait Foo { fn do(&self); }
// impl Foo for MyType { fn do(&self) {...} }
// generics: fn f<T: Foo>(t: T) {}
// impl Trait in returns: fn make() -> impl Iterator<Item=i32> {}

rust_error.cheat:
// Error handling cheat
// - fn f() -> Result<T, E> { ... }
// - propagate: let v = foo()?;
// - wrap: Err(format!("context: {}", e)) or use thiserror/anyhow for ergonomics
// - prefer Result in libraries, panic sparingly

