rust_memory.cheat:
// Memory cheat
// - Use Box for heap allocation, Rc/Arc for shared ownership
// - Avoid unnecessary clones; prefer borrowing
// - Use Vec::with_capacity to avoid reallocations
// - Use Miri and sanitizers to validate unsafe code

rust_std.cheat:
// Stdlib cheat
// - streams: Read/Write, BufRead for buffered IO
// - collections: Vec, HashMap, BTreeMap, HashSet
// - threading: std::thread, std::sync::{Mutex,RwLock,Condvar,Arc}
// - networking: std::net for blocking sockets; tokio for async

rust_ffi.cheat:
// FFI cheat
// - extern "C" and #[no_mangle] to export functions
// - #[repr(C)] for struct layout
// - prefer CStr/CString for strings and clearly document ownership
// - use bindgen for generating Rust bindings to C headers

rust_macros.cheat:
// Macro cheat
// - macro_rules! for declarative macros
// - proc-macro crates for derive/attribute macros
// - use syn/quote to parse and generate token streams
// - document generated code and avoid surprising captures

examples.code:
// macro_rules! example
macro_rules! vec2 { ($a:expr,$b:expr) => { Vec::from([$a,$b]) }; }
let v = vec2!(1,2);

